 36	/* Initialize the storage at the beginning of the run. */
 37	
 38	void
 39	init_storage ()
 40	{
 41	
 42	  /* Functions: we start with none and ask for more. */
 43	  f_count = 0;
 44	  more_functions ();
 45	  f_names[0] = "(main)";
 46	
 47	  /* Variables. */
 48	  v_count = 0;
 49	  more_variables ();
 50	  
 51	  /* Arrays. */
 52	  a_count = 0;
 53	  more_arrays ();
 54	
 55	  /* Other things... */
 56	  ex_stack = NULL;
 57	  fn_stack = NULL;
 58	  i_base = 10;
 59	  o_base = 10;
 60	  scale  = 0;
 61	#if defined(READLINE) || defined(LIBEDIT)
 62	  n_history = -1;	
 63	#endif
 64	  c_code = FALSE;
 65	  bc_init_numbers();
 66	}
