221	/*  Pop the function execution stack and return the top. */
222	
223	int
224	fpop()
225	{
226	  fstack_rec *temp;
227	  int retval;
228	  
229	  if (fn_stack != NULL)
230	    {
231	      temp = fn_stack;
232	      fn_stack = temp->s_next;
233	      retval = temp->s_val;
234	      free (temp);
235	    }
236	  else
237	    {
238	      retval = 0;
239	      rt_error ("function stack underflow, contact maintainer.");
240	    }
241	  return (retval);
242	}
