245	/* Push VAL on to the function stack. */
246	
247	void
248	fpush (val)
249	     int val;
250	{
251	  fstack_rec *temp;
252	  
253	  temp = (fstack_rec *) bc_malloc (sizeof (fstack_rec));
254	  temp->s_next = fn_stack;
255	  temp->s_val = val;
256	  fn_stack = temp;
257	}
