   544		  break;
   545	
   546	#if defined(READLINE) || defined(LIBEDIT)
   547		case 3:
   548		  if (toobig)
   549		    {
   550		      temp = -1;
   551		      rt_warn ("history too large, set to unlimited");
   552		      UNLIMIT_HISTORY;
   553		    }
   554		  else
   555		    {
   556		      n_history = temp;
