   241	/* Initialize the code generator the parser. */
   242	
   243	void
   244	init_gen ()
   245	{
   246	  /* Get things ready. */
   247	  break_label = 0;
   248	  continue_label = 0;
   249	  next_label  = 1;
   250	  out_count = 2;
