   260	/* generate code STR for the machine. */
   261	
   262	void
   263	generate (str)
   264	      char *str;
   265	{
   266	  did_gen = TRUE;
   267	  if (compile_only)
   268	    {
   269	      printf ("%s",str);
   270	      out_count += strlen(str);
   271	      if (out_count > 60)
   272		{
   273		  printf ("\n");
   274		  out_count = 0;
   275		}
   276	    }
   277	  else
   278	    load_code (str);
   279	}
