   282	/* Execute the current code as loaded. */
   283	
   284	void
   285	run_code()
   286	{
   287	  /* If no compile errors run the current code. */
   288	  if (!had_error && did_gen)
   289	    {
   290	      if (compile_only)
   291		{
   292		  printf ("@r\n"); 
   293		  out_count = 0;
   294		}
   295	      else
   296		execute ();
   297	    }
   298	
   299	  /* Reinitialize the code generation and machine. */
   300	  if (did_gen)
   301	    init_gen();
   302	  else
   303	    had_error = FALSE;
   304	}
